def compare_one(a, b):
    def to_float(x):
        if isinstance(x, str):
            x = x.replace(',', '.')
        return float(x)

    num_a = to_float(a)
    num_b = to_float(b)

    if num_a > num_b:
        return a
    elif num_b > num_a:
        return b
    else:
        return None
